    (ans+=(up-lw+mod+1)%mod)%=mod;

  }

  coutn(ans);

}











int main(void){

  std::cout << std::fixed << std::setprecision(20);

  cin.tie(0);

  ios::sync_with_stdio(false);

  solve();

  return 0;

}

